css:
body {
  -webkit-font-smoothing: antialiased;
  color: #e0ddd5;
  margin: 0;
  padding: 0;
  max-height: 1000px;
  overflow: hidden;
  box-sizing: border-box;
  background-color: #602E17;

}

#canvas {
  width: 1004px;
  height: 637px;
  position: relative;
  background-image: url("https://domaineampelhus.fr/wp-content/uploads/2026/05/CARTE-MEMBRE11.png");
}

/*the following is to scale the layout*/
html {
  font-family: Avenir, arial, sans-serif;
  box-sizing: border-box;
  background-color: #602E17;
  color: #e0ddd5;
}

div {
  display: flex;
}
.title{ 
  color: #FFF;
  font-size: 48px;
  font-weight: bold;
  font-style: bold;
  max-width: 1000px;
  line-height: 1.2;
  position: absolute;
}
.user {
  font-size: 48px;
  max-width: 1000px;
  line-height: 1.2;
  position: absolute;
  left: 7.2%;
  top: 30%;
  text-transform: uppercase;color: #FFF;
}

.label {
  color: #c5c4bb;
  left: 18.7%;
  font-size: 30px;
  position: absolute;
}
.labelTitle {
  color: #C88B67;
  left: 18.7%;
  font-size: 26px;
  font-weight: 800;
  position: absolute;
}
.cepage {
  top: 61%;
}

.annee {
  top: 74%;
  left: 18.4%;
}

.coord {
  top: 87%;
  left: 18.4%;
}

.num { 
  color: #C88B67;
  position: absolute;
    font-size: 40px;
    font-weight: 800;font: "arial";
}
.subtitle{ 
  text-align: center;
  color: #C88B67;
    position: absolute;
    font-style: italic;
    font: "arial";
    font-size: 20px;
}

